@@ -2531,10 +2531,44 @@ fn runServer(allocator: std.mem.Allocator, model_path: []const u8, host: []const
     };
     defer prof.deinit(allocator);

+    // Check current memory pressure and adjust GPU layers if needed
+    var mem_monitor = try memory_monitor.MemoryMonitor.init(allocator);
+    defer mem_monitor.deinit();
+
+    const mem_stats = try mem_monitor.getStats();
+    std.debug.print("Current memory: {d:.1} GB used / {d:.1} GB total ({d:.0}%)\n", .{
+        mem_stats.used_gb,
+        mem_stats.total_gb,
+        mem_stats.usage_percent,
+    });
+
+    // If memory pressure is high, reduce GPU layers to leave headroom
+    var adjusted_gpu_layers = prof.optimal_config.n_gpu_layers;
+    if (mem_stats.pressure == .high or mem_stats.pressure == .critical) {
+        // Reduce GPU layers by 50% when memory is tight
+        adjusted_gpu_layers = @max(1, @divTrunc(prof.optimal_config.n_gpu_layers, 2));
+        std.debug.print("⚠️  High memory pressure detected, reducing GPU layers: {} -> {}\n", .{
+            prof.optimal_config.n_gpu_layers,
+            adjusted_gpu_layers,
+        });
+    } else if (mem_stats.available_gb < prof.memory_estimate.total_gb) {
+        // Not enough free memory for full profile, scale down proportionally
+        const scale = @max(0.3, mem_stats.available_gb / prof.memory_estimate.total_gb);
+        adjusted_gpu_layers = @intFromFloat(@as(f32, @floatFromInt(prof.optimal_config.n_gpu_layers)) * scale);
+        adjusted_gpu_layers = @max(1, adjusted_gpu_layers);
+        std.debug.print("⚠️  Limited memory ({d:.1} GB free), reducing GPU layers: {} -> {}\n", .{
+            mem_stats.available_gb,
+            prof.optimal_config.n_gpu_layers,
+            adjusted_gpu_layers,
+        });
+    }
+
     std.debug.print("Loading model for server...\n", .{});

-    // Load model
-    var model = llama.loadWithProfile(prof) catch |err| {
+    // Load model with potentially adjusted GPU layers
+    var model = llama.Model.load(model_path, .{
+        .n_gpu_layers = adjusted_gpu_layers,
+    }) catch |err| {
         std.debug.print("Failed to load model: {}\n", .{err});
         return err;
     };
@@ -2545,11 +2579,20 @@ fn runServer(allocator: std.mem.Allocator, model_path: []const u8, host: []const

     std.debug.print("Initializing scheduler...\n", .{});

+    // Reduce context size proportionally if GPU layers were reduced
+    const context_scale = @as(f32, @floatFromInt(adjusted_gpu_layers)) / @as(f32, @floatFromInt(prof.optimal_config.n_gpu_layers));
+    const adjusted_ctx: u32 = @intFromFloat(@as(f32, @floatFromInt(prof.optimal_config.n_ctx)) * context_scale);
+    const final_ctx = @max(512, adjusted_ctx); // Minimum 512 tokens
+
+    if (final_ctx != prof.optimal_config.n_ctx) {
+        std.debug.print("⚠️  Adjusted context size: {} -> {} tokens\n", .{ prof.optimal_config.n_ctx, final_ctx });
+    }
+
     // Create scheduler with appropriate context size
     var scheduler = try Scheduler.init(allocator, &model, .{
         .max_cells = 1,
-        .context_per_cell = prof.optimal_config.n_ctx,
-        .batch_size = prof.optimal_config.n_batch,
+        .context_per_cell = final_ctx,
+        .batch_size = @min(prof.optimal_config.n_batch, final_ctx),
         .enable_tools = true,
         .adaptive_mode = false,
     });
